"""Utility functions used by PISM's regression tests"""

import PISM
import numpy as np
import uuid

def filename(prefix):
    return prefix + str(uuid.uuid4()) + ".nc"

def shallow_grid(Mx=3, My=5, Lx=10e3, Ly=20e3):
    "Create a shallow computational grid for testing"
    return PISM.Grid.Shallow(PISM.Context().ctx,
                             Lx, Ly, 0, 0, Mx, My,
                             PISM.CELL_CORNER,
                             PISM.NOT_PERIODIC)

def sample(vec, i=0, j=0):
    "Sample a PISM array"
    with PISM.vec.Access(nocomm=vec):
        return vec[i, j]

def check(vec, value):
    "Check if values of vec are almost equal to value."
    np.testing.assert_almost_equal(sample(vec), value)

def check_difference(A, B, value):
    "Check if the difference between A and B is almost equal to value."
    np.testing.assert_almost_equal(sample(A) - sample(B), value)

def check_ratio(A, B, value):
    "Check if the ratio of A and B is almost equal to value."
    b = sample(B)
    if b != 0:
        np.testing.assert_almost_equal(sample(A) / b, value)
    else:
        np.testing.assert_almost_equal(sample(A), 0.0)

def create_scalar_forcing(file_name, variable_name, units, values, times, time_bounds=None):
    "Create a dummy scalar forcing file (delta_T, etc)."

    ctx = PISM.Context()

    use_bounds = time_bounds is not None

    if use_bounds and times is None:
        # override times
        times = []
        for k in range(len(values)):
            times.append(0.5 * (time_bounds[2 * k + 0] +
                                time_bounds[2 * k + 1]))

    time = ctx.time.metadata(use_bounds)

    try:
        output = PISM.util.prepare_output(file_name, append=True, time=time)
    except:
        output = PISM.util.prepare_output(file_name, append=False, time=time)

    variable = PISM.VariableMetadata(variable_name, time.unit_system())
    variable.set_time_dependent(True).units(units)

    output.define_variable(variable)

    if use_bounds:
        bounds = ctx.time.bounds_metadata()
        output.define_variable(bounds)

        output.write_array(bounds.get_name(), [0, 0], [len(times), 2],
                           np.array(time_bounds, dtype=np.float64).data)

    output.write_array(time.get_name(), [0], [len(times)],
                       np.array(times, dtype=np.float64).data)

    output.write_array(variable_name, [0], [len(values)],
                       np.array(values, dtype=np.float64).data)

    output.close()

def create_forcing(grid, file_name, variable_name, units, values,
                   time_units=None, times=None, time_bounds=None):
    "Create a dummy 2D forcing without spatial variability"

    if times is None and time_bounds is None:
        raise ValueError("both times and time_bounds are None")

    if time_units is None:
        time_units = "seconds since 1-1-1"

    ctx = grid.ctx()

    use_bounds = time_bounds is not None

    time = ctx.time().metadata(use_bounds)
    time.units(time_units)

    v = PISM.Scalar(grid, variable_name)
    v.metadata().set_string("units", units)

    output = PISM.util.prepare_output(file_name, append_time=False, time=time)

    output.define_variable(v.metadata())

    if time_bounds is not None:
        bounds = ctx.time().bounds_metadata()
        output.define_variable(bounds)

        assert len(values) + 1 == len(time_bounds)
        for k in range(len(values)):
            if times is not None:
                output.append_time(times[k])
            else:
                output.append_time(time_bounds[k + 1])

            # write time bounds
            output.write_array(bounds, [k, 0], [1, 2], (time_bounds[k], time_bounds[k + 1]))

            v.set(values[k])
            v.write(output)
    else:
        for k in range(len(values)):
            output.append_time(times[k])
            v.set(values[k])
            v.write(output)

    output.close()
